                <div class="title text-black d-flex mb-3 gap-2 align-items-center"><span>–í–∞—à–∞ –ø–∞—Ä—Ç–Ω—ë—Ä—Å–∫–∞—è —Å–∫–∏–¥–∫–∞</span><span class="person-sale">{$sale}%</span></div>
                {if $inn_tmp[1] > 1}
                    {if $_modx->user.field_iudiscount}
                        <div class="title text-black d-flex mb-3 gap-2 align-items-center"><span>–û–±—ä–µ–º –∑–∞–∫—É–ø–æ–∫ –≤ —Ç–µ–∫—É—â–µ–º –∫–≤–∞—Ä—Ç–∞–ª–µ</span><span class="purchase-volume">{$_modx->user.field_summ} ‚ÇΩ</span></div>
                        {if $_modx->user.notresident != '1'}
                            {set $rebeit = $_modx->user.rebeit ?: '!quarter' | snippet} {*–¥–∞—Ç–∞ –∫–≤–∞—Ä—Ç–∞–ª*}
                            {set $field_summ = '!end_date' | snippet : [
                                'date' => $rebeit,
                                'field_summ' => $_modx->user.field_summ
                            ]}
                            {switch $_modx->user.field_iudiscount}
                                {case 30}
                                    <div class="achievement d-flex flex-wrap mb-4">
                                        {set $porog = 400000}
                                        {set $range = $porog - $.php.round($field_summ)}
                                        {set $range_percent = $.php.round($field_summ)}
                                        {set $range_percent = ($field_summ / $porog) * 100}
                                        {set $porog_tmp = 650000}
                                        {set $range_tmp = $porog_tmp - $.php.round($field_summ)}
                                        {set $range_percent_tmp = ($field_summ / $porog_tmp) * 100}
                                        {if $field_summ > $porog}
                                            {set $field_summ = $.php.round($field_summ)}
