                                            <div class="col-12">
                                                <div class="d-flex align-items-center gap-2 mb-5">
                                                    <span class="col-auto value">0 ‚ÇΩ</span>
                                                    <div class="col block-range">
                                                        <div class="range-full" style="width: 100%"></div>
                                                        <div class="range purple" style="width: {$range_percent}%"></div>
                                                        <span class="active_summ" style="left: calc({$range_percent}% - 10px);">{$field_summ | number : 0 : '.' : '&nbsp;'}&nbsp;‚ÇΩ</span>
                                                    </div>
                                                    <span class="col-auto value">{$porog | number : 0 : '.' : ' '} ‚ÇΩ</span>
                                                </div>
                                            </div>
                                        </div>
                                        <div class="col-xl-auto">
                                            <div class="title-small mb-1">–î–ª—è –ø–æ–≤—ã—à–µ–Ω–∏—è –ø–∞—Ä—Ç–Ω–µ—Ä—Å–∫–æ–π —Å–∫–∏–¥–∫–∏ –¥–æ 50% –≤ —Å–ª–µ–¥—É—é—â–µ–º –∫–≤–∞—Ä—Ç–∞–ª–µ - –ø—Ä–∏–æ–±—Ä–µ—Ç–∏—Ç–µ –ª–∏—Ü–µ–Ω–∑–∏–∏ –µ—â–µ –Ω–∞ <span class="text-black">{$range_tmp | number : 0 : '.' : ' '} ‚ÇΩ</span> –¥–æ {$rebeit}</div>
                                            <div class="col-12">
                                                <div class="d-flex align-items-center gap-2 mb-3">
                                                    <span class="col-auto value">0 ‚ÇΩ</span>
                                                    <div class="col block-range">
                                                        <div class="range-full" style="width: 100%"></div>
                                                        <div class="range" style="width: {$range_percent_tmp}%"></div>
                                                        <span class="active_summ" style="left: calc({$range_percent_tmp}% - 10px);">{$field_summ | number : 0 : '.' : '&nbsp;'}&nbsp;‚ÇΩ</span>
                                                    </div>
                                                    <span class="col-auto value">{$porog_tmp | number : 0 : '.' : ' '} ‚ÇΩ</span>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                {case 40}
                                    <div class="achievement d-flex flex-wrap mb-4">
                                        {set $porog = 650000}
                                        {set $range = $porog - $.php.round($field_summ)}
                                        {set $range_percent = $.php.round($field_summ)}
                                        {set $range_percent = ($field_summ / $porog) * 100}
                                        {set $range_tmp = 400000 - $.php.round($field_summ)}
                                        {set $range_percent_tmp = ($field_summ / 400000) * 100}
                                        {if $field_summ > 400000}
                                            {set $field_summ = $.php.round($field_summ)}
                                            {set $range_percent_tmp = 100}
                                            {set $range_tmp = 0}
                                            {if $field_summ > $porog}
                                                {set $range = 0}
                                                {set $range_percent = 100}
                                            {/if}
                                        {/if}
                                        <div class="d-flex flex-column align-items-start">
                                            <div class="col-xl-auto mb-3">
                                                <div class="title-small mb-1">–î–ª—è —Å–æ—Ö—Ä–∞–Ω–µ–Ω–∏—è —Ä–∞–∑–º–µ—Ä–∞ –ø–∞—Ä—Ç–Ω–µ—Ä—Å–∫–æ–π —Å–∫–∏–¥–∫–∏ –≤ —Å–ª–µ–¥—É—é—â–µ–º –∫–≤–∞—Ä—Ç–∞–ª–µ - –ø—Ä–∏–æ–±—Ä–µ—Ç–∏—Ç–µ –ª–∏—Ü–µ–Ω–∑–∏–∏ –µ—â–µ –Ω–∞ <span class="text-black">{$range_tmp | number : 0 : '.' : ' '} ‚ÇΩ</span> –¥–æ {$rebeit}</div>
                                                <div class="col-12">
                                                    <div class="d-flex align-items-center gap-2 mb-5">
                                                        <span class="col-auto value">0 ‚ÇΩ</span>
                                                        <div class="col block-range">
                                                            <div class="range-full" style="width: 100%"></div>
                                                            <div class="range" style="width: {$range_percent_tmp}%"></div>
                                                            <span class="active_summ" style="left: calc({$range_percent_tmp}% - 10px);">{$field_summ | number : 0 : '.' : '&nbsp;'}&nbsp;‚ÇΩ</span>
                                                        </div>
                                                        <span class="col-auto value">{400000 | number : 0 : '.' : ' '} ‚ÇΩ</span>
                                                    </div>
                                                </div>
                                            </div>
                                            <div class="col-xl-auto">
                                                <div class="title-small mb-1">–î–ª—è –ø–æ–≤—ã—à–µ–Ω–∏—è –ø–∞—Ä—Ç–Ω–µ—Ä—Å–∫–æ–π —Å–∫–∏–¥–∫–∏ –¥–æ 50% –≤ —Å–ª–µ–¥—É—é—â–µ–º –∫–≤–∞—Ä—Ç–∞–ª–µ - –ø—Ä–∏–æ–±—Ä–µ—Ç–∏—Ç–µ –ª–∏—Ü–µ–Ω–∑–∏–∏ –µ—â–µ –Ω–∞ <span class="text-black">{$range | number : 0 : '.' : ' '} ‚ÇΩ</span> –¥–æ {$rebeit}</div>
                                                <div class="col-12">
                                                    <div class="d-flex align-items-center gap-2 mb-3">
                                                        <span class="col-auto value">0 ‚ÇΩ</span>
                                                        <div class="col block-range">
                                                            <div class="range-full" style="width: 100%"></div>
                                                            <div class="range purple" style="width: {$range_percent}%"></div>
                                                            <span class="active_summ" style="left: calc({$range_percent}% - 10px);">{$field_summ | number : 0 : '.' : '&nbsp;'}&nbsp;‚ÇΩ</span>
                                                        </div>
                                                        <span class="col-auto value">{$porog | number : 0 : '.' : ' '} ‚ÇΩ</span>
                                                    </div>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                {case 50}
                                    <div class="achievement d-flex flex-wrap mb-4">
                                        {set $porog = 650000}
                                        {set $range = $porog - $.php.round($field_summ)}
                                        {set $range_percent = $.php.round($field_summ)}
                                        {set $range_percent = ($field_summ / $porog) * 100}
                                        {if $field_summ > $porog}
                                            {set $field_summ = $.php.round($field_summ)}
                                            {set $range_percent = 100}
                                            {set $range = 0}
                                        {/if}
                                        <div class="col-xl-auto">
                                            <div class="title-small mb-1">–î–ª—è —Å–æ—Ö—Ä–∞–Ω–µ–Ω–∏—è —Ä–∞–∑–º–µ—Ä–∞ –ø–∞—Ä—Ç–Ω–µ—Ä—Å–∫–æ–π —Å–∫–∏–¥–∫–∏ –≤ —Å–ª–µ–¥—É—é—â–µ–º –∫–≤–∞—Ä—Ç–∞–ª–µ - –ø—Ä–∏–æ–±—Ä–µ—Ç–∏—Ç–µ –ª–∏—Ü–µ–Ω–∑–∏–∏ –µ—â–µ –Ω–∞ <span class="text-black">{$range | number : 0 : '.' : ' '} ‚ÇΩ</span> –¥–æ {$rebeit}</div>
                                            <div class="col-12">
                                                <div class="d-flex align-items-center gap-2 mb-3">
                                                    <span class="col-auto value">0 ‚ÇΩ</span>
                                                    <div class="col block-range">
                                                        <div class="range-full" style="width: 100%"></div>
                                                        <div class="range" style="width: {$range_percent}%"></div>
                                                        <span class="active_summ" style="left: calc({$range_percent}% - 10px);">{$field_summ | number : 0 : '.' : '&nbsp;'}&nbsp;‚ÇΩ</span>
                                                    </div>
                                                    <span class="col-auto value">{$porog | number : 0 : '.' : ' '} ‚ÇΩ</span>
                                                </div>
                                            </div>
                                        </div>
                                    </div>

                                {default}

                            {/switch}
                        {/if}
                    {else}
                        {set $rebeit = $_modx->user.rebeit ?: '!quarter' | snippet}
                        {set $field_summ = '!end_date' | snippet : [
                            'date' => $rebeit,
                            'field_summ' => $_modx->user.field_summ
                        ]}
                        <div class="achievement d-flex flex-wrap mb-4">
                            {if $_modx->user.field_ceil}
                                {set $porog = $.php.round($_modx->user.field_ceil)}
                            {/if}
                            {set $range = $porog - $.php.round($field_summ)}
                            {set $range_percent = $.php.round($field_summ)}
                            {set $range_percent = ($field_summ / $porog) * 100}
                            {if $field_summ > $porog}
                                {set $field_summ = 0}
                                {set $range_percent = 0}
                            {/if}
                            <div class="col-xl-auto">
                                <div class="title-small mb-1">–î–ª—è –ø–æ–¥—Ç–≤–µ—Ä–∂–¥–µ–Ω–∏—è –ø–∞—Ä—Ç–Ω—ë—Ä—Å–∫–æ–≥–æ —Å—Ç–∞—Ç—É—Å–∞ –æ—Å—Ç–∞–ª–æ—Å—å –ø—Ä–∏–æ–±—Ä–µ—Å—Ç–∏ –ª–∏—Ü–µ–Ω–∑–∏–π –Ω–∞ <span class="text-black">{$range | number : 0 : '.' : ' '} ‚ÇΩ</span> –¥–æ {$rebeit}</div>
