                                    <div class="block-range">
                                        <div class="range-full" style="width: 100%"></div>
                                        <div class="range" style="width: {$range_percent}%"></div>
                                        <div class="d-flex align-items-center justify-content-between pt-4">
                                            <span class="text-black">{$field_summ | number : 0 : '.' : ' '} ‚ÇΩ</span>
                                            <span class="text-black">{$porog | number : 0 : '.' : ' '} ‚ÇΩ</span>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    {/if}
                    {if $_modx->user.field_marketing}
                        {set $date = '' | date : "Y"}
                        <div class="title text-black mb-3">–í–∞—à–∏ –ø–∞—Ä—Ç–Ω—ë—Ä—Å–∫–∏–µ —Ä–∏–±–µ–π—Ç—ã (–¥–µ–π—Å—Ç–≤—É–µ—Ç –¥–æ 31.12.{$date})</div>
                        <div class="title-small mb-2">–í {$date} –≥–æ–¥—É –≤—ã –º–æ–∂–µ—Ç–µ –ø–æ—Ç—Ä–∞—Ç–∏—Ç—å –Ω–∞ –º–∞—Ä–∫–µ—Ç–∏–Ω–≥ –∏–ª–∏ –æ–±—É—á–µ–Ω–∏–µ - <span class="text-black">{$_modx->user.field_marketing | number : 0 : '.' : ' '} ‚ÇΩ</span></div>
                        <div class="title-small mb-2">–ù–∞ –¥–∞–Ω–Ω—ã–π –º–æ–º–µ–Ω—Ç –≤—ã —É–∂–µ –ø–æ—Ç—Ä–∞—Ç–∏–ª–∏ - <span class="text-black">{$_modx->user.field_sold ? $_modx->user.field_sold : 0 | number : 0 : '.' : ' '} ‚ÇΩ</span></div>
                        {set $range_marketing = $_modx->user.field_marketing - $.php.round($_modx->user.field_sold ? $_modx->user.field_sold : 0)}
                        {set $range_marketing_percent = $.php.round($_modx->user.field_sold ? $_modx->user.field_sold : 0)}
                        {set $range_marketing_percent = ($range_marketing_percent / $_modx->user.field_marketing) * 100}
                        <div class="title-small mb-4">–û—Å—Ç–∞–ª–æ—Å—å –ø–æ—Ç—Ä–∞—Ç–∏—Ç—å - <span class="text-red">{$range_marketing | number : 0 : '.' : ' '} ‚ÇΩ</span></div>
                        <div class="pie-chart mb-4">
                            <svg class="pie" width="202" viewBox="0 0 37 37">
                                <circle r="15.9155" cx="50%" cy="50%"></circle>
                                <circle r="15.9155" cx="50%" cy="50%" style="stroke-dasharray: {$range_marketing_percent} 100;"></circle>
                                <text x="50%" y="50%">{$range_marketing | number : 0 : '.' : ' '} ‚ÇΩ</text>
                            </svg>
                        </div>
                    {/if}
                    {if $_modx->user.field_nfr}
                        {$_modx->lexicon->load('core:site')}
                        {set $nfr = $_modx->user.field_nfr}
                        {set $nfr = $nfr | split : ";"}
                        <div class="title text-black mt-3 mb-3">–í–∞—à–∞ NFR-–ª–∏—Ü–µ–Ω–∑–∏—è</div>

                        <div class="section-nfr d-flex flex-wrap gap-4 gap-lg-5">
                            <div class="col-12 col-lg-auto d-flex flex-column">
                                <ul class="nav nav-pills mb-3 gap-2 mb-4" id="pills-tab" role="tablist">
                                    {foreach $nfr as $key => $item}
                                        {if $key < 3}
                                            {set $values = $item | split : ":"}
                                            {if $item@first}
