                                                    <button class="nav-nfr active" id="pills-{$key}-tab" data-bs-toggle="pill" data-bs-target="#pills-{$key}" type="button" role="tab" aria-controls="pills-{$key}" aria-selected="true">{('site_profile_name_' ~ $values[0]) | lexicon}</button>
                                                </li>
                                            {else}
                                                <li class="nav-item" role="presentation">
                                                    <button class="nav-nfr" id="pills-{$key}-tab" data-bs-toggle="pill" data-bs-target="#pills-{$key}" type="button" role="tab" aria-controls="pills-{$key}" aria-selected="false">{('site_profile_name_' ~ $values[0]) | lexicon}</button>
                                                </li>
                                            {/if}
                                        {/if}
                                    {/foreach}
                                </ul>
                                <div class="tab-content" id="pills-tabContent">
                                    {foreach $nfr as $key => $item}
                                        {set $freePercentage = 0}
                                        {set $values = $item | split : ":"}
                                        {set $nums = $values[1] | split : ","}
