                label: 'Dataset 1'
            }],
            labels: [
                {foreach $catResults as $cr}
                    "{$cr.cat_name} {$cr.cat_point}{if $test.type == 1} –∏–∑ {$cr.max_point}{/if}",
                {/foreach}
            ]
        },
        options: {
            responsive: true
        }
    };

    {if !$check_ajax}
        onload_chart = function() {
    {/if}
