    $response = $modx->runProcessor('/security/login', $logindata);
    // –ø—Ä–æ–≤–µ—Ä—è–µ–º, —É—Å–ø–µ—à–Ω–æ –ª–∏
    if ($response->isError()) {
      // –ø—Ä–æ–∏–∑–æ—à–ª–∞ –æ—à–∏–±–∫–∞, –Ω–∞–ø—Ä–∏–º–µ—Ä –Ω–µ–≤–µ—Ä–Ω—ã–π –ø–∞—Ä–æ–ª—å
      $modx->log(modX::LOG_LEVEL_ERROR, 'Login error. Message: '.$response->getMessage());
      return '–ù–µ —É–¥–∞–ª–æ—Å—å –∞–≤—Ç–æ—Ä–∏–∑–æ–≤–∞—Ç—å –ø–æ–ª—å–∑–æ–≤–∞—Ç–µ–ª—è!';
    } */
