        $moduleState = 'new';
    }

    $moduleLessonsHtml = '';

    usort($lessonRows, function ($a, $b) {
        $aSort = (int)$a->get('sort_order');
        $bSort = (int)$b->get('sort_order');
        if ($aSort !== $bSort) {
            return $aSort < $bSort ? -1 : 1;
        }

        $aId = (int)$a->get('id');
        $bId = (int)$b->get('id');
        if ($aId === $bId) {
            return 0;
        }

        return $aId < $bId ? -1 : 1;
    });

    usort($moduleActivityRows, function ($a, $b) {
        $aSort = (int)$a['sort_order'];
        $bSort = (int)$b['sort_order'];
        if ($aSort !== $bSort) {
            return $aSort < $bSort ? -1 : 1;
        }

        $aId = (int)$a['id'];
        $bId = (int)$b['id'];
        if ($aId === $bId) {
