    $moduleItemsCountText = $moduleItemsTotal . ' ' . trainingCoursePagePlural($moduleItemsTotal, array('–º–∞—Ç–µ—Ä–∏–∞–ª', '–º–∞—Ç–µ—Ä–∏–∞–ª–∞', '–º–∞—Ç–µ—Ä–∏–∞–ª–æ–≤'));
