if (!function_exists('usertestBuildUrlTraining')) {
    function usertestBuildUrlTraining($baseUrl, array $params)
    {
        $baseUrl = html_entity_decode(trim((string)$baseUrl), ENT_QUOTES, 'UTF-8');
        if ($baseUrl === '') {
            return '';
        }

        $hash = '';
        $hashPos = strpos($baseUrl, '#');
        if ($hashPos !== false) {
            $hash = substr($baseUrl, $hashPos);
            $baseUrl = substr($baseUrl, 0, $hashPos);
        }

        $parts = parse_url($baseUrl);
        if (!is_array($parts)) {
            return $baseUrl;
        }

        $query = array();
        if (!empty($parts['query'])) {
            parse_str($parts['query'], $query);
        }

        unset($query['_ut_modal_refresh'], $query['result_id']);
        foreach ($params as $key => $value) {
            if ($value === null || $value === '') {
                unset($query[$key]);
            } else {
                $query[$key] = $value;
            }
        }

        $url = '';
        if (!empty($parts['scheme'])) {
            $url .= $parts['scheme'] . '://';
        }
        if (!empty($parts['user'])) {
            $url .= $parts['user'];
            if (!empty($parts['pass'])) {
                $url .= ':' . $parts['pass'];
            }
            $url .= '@';
        }
        if (!empty($parts['host'])) {
            $url .= $parts['host'];
        }
        if (!empty($parts['port'])) {
            $url .= ':' . $parts['port'];
        }
        $url .= !empty($parts['path']) ? $parts['path'] : '';

        $queryString = http_build_query($query, '', '&');
        if ($queryString !== '') {
            $url .= '?' . $queryString;
        }

        return $url . $hash;
    }
}

