        }

        $_GET['test_id'] = $testId;
        $_REQUEST['test_id'] = $testId;
        $_GET['id'] = $testId;
        $_REQUEST['id'] = $testId;
        if ($step !== '') {
            $_GET['step'] = $step;
            $_REQUEST['step'] = $step;
        }
        if ($resultId > 0) {
            $_GET['result_id'] = $resultId;
            $_REQUEST['result_id'] = $resultId;
        }
        if ($reset !== null) {
            $_GET['reset'] = 1;
            $_REQUEST['reset'] = 1;
        }

        return $modx->runSnippet('UserTest', array(
            'id' => $testId,
            'AjaxMode' => 1,
            'training_activity_id' => $activityId,
            'training_activity_page_url' => $pageUrl,
            'training_activity_course_id' => $courseId,
            'training_activity_module_id' => $moduleId,
            'training_activity_test_link_id' => $activityId,
            'training_activity_min_pass_percent' => $minPassPercentText,
            'training_activity_back_url' => $backUrl,
            'training_activity_restart_url' => $restartUrl,
            'training_activity_answer_url' => $answerUrlTpl,
        ));
    }


    if ($screen === 'instruction') {
        return trainingActivityRenderFile2($corePath, 'training/activity/instruction.tpl', array(
            'instruction_html' => $testInstruction !== '' ? $testInstruction : '<p>–ü–µ—Ä–µ–¥ –æ—Ç–≤–µ—Ç–æ–º –≤–Ω–∏–º–∞—Ç–µ–ª—å–Ω–æ –ø—Ä–æ—á–∏—Ç–∞–π—Ç–µ —Ç–µ–∫—Å—Ç –≤–æ–ø—Ä–æ—Å–∞. –ó–∞—Ç–µ–º –≤—ã–±–µ—Ä–∏—Ç–µ –ø—Ä–∞–≤–∏–ª—å–Ω—ã–π –≤–∞—Ä–∏–∞–Ω—Ç –æ—Ç–≤–µ—Ç–∞. –í –Ω–µ–∫–æ—Ç–æ—Ä—ã—Ö –≤–æ–ø—Ä–æ—Å–∞—Ö –º–æ–∂–µ—Ç –±—ã—Ç—å –Ω–µ—Å–∫–æ–ª—å–∫–æ –ø—Ä–∞–≤–∏–ª—å–Ω—ã—Ö –æ—Ç–≤–µ—Ç–æ–≤. –ù–∞–∂–º–∏—Ç–µ –∫–Ω–æ–ø–∫—É ¬´–ù–∞—á–∞—Ç—å —Ç–µ—Å—Ç¬ª, —á—Ç–æ–±—ã –ø–µ—Ä–µ–π—Ç–∏ –∫ –≤–æ–ø—Ä–æ—Å–∞–º.</p>',
            'min_pass_percent' => $minPassPercentText,
            'attempts_text' => $attemptsText,
            'start_url' => trainingActivityEsc2($testUrl),
            'back_button_html' => $backUrl !== '' ? '<a href="' . trainingActivityEsc2($backUrl) . '" class="btn btn-test col-auto text-decoration-none"><span>–ù–∞–∑–∞–¥ –∫ –∫—É—Ä—Å—É</span><img src="theme/images/training/tests/arrow-rotate-ico.svg" class="img-svg d-none d-sm-block"></a>' : '',
        ));
    }

    return trainingActivityRenderFile2($corePath, 'training/activity/start.tpl', array(
        'title' => trainingActivityEsc2($testTitle !== '' ? $testTitle : '–¢–µ—Å—Ç'),
        'description_html' => $testDescription !== '' ? $testDescription : '<p>–ù–∞–∂–º–∏—Ç–µ ¬´–ù–∞—á–∞—Ç—å —Ç–µ—Å—Ç¬ª, —á—Ç–æ–±—ã –ø–µ—Ä–µ–π—Ç–∏ –∫ –∏–Ω—Å—Ç—Ä—É–∫—Ü–∏–∏.</p>',
